+                .join(", ");
+            parts.push(format!("Filters: {applied}"));
+        }
+        if !assistance.did_you_mean.is_empty() {
+            let suggestions = assistance
+                .did_you_mean
+                .iter()
+                .map(|hint| format!("{} -> {}", hint.token, hint.suggested_field))
+                .collect::<Vec<_>>()
+                .join(", ");
+            parts.push(format!("Did you mean: {suggestions}"));
+        }
+        if parts.is_empty() {
+            None
+        } else {
+            Some(parts.join(" | "))
